const input = $input.first().json;
const body = input.body || input;
const url = body.url || '';
const title = body.title || 'Laravel/PHP Job';
const description = body.description || '';

let context = '';
if (description) {
  context = description;
} else if (url) {
  context = 'Job URL: ' + url + '. Please write a strong proposal for a Laravel/PHP developer role based on the job title.';
} else {
  context = 'No description provided. Write based on title only.';
}

const sysPrompt = 'You are an expert PHP/Laravel developer (8+ yrs). Specialties: Laravel apps, payment gateway integrations (Stripe, PayPal), REST APIs, MySQL, PHP debugging & optimization. Write a compelling Upwork proposal (150-250 words). Rules: 1) Hook showing you understand THEIR specific problem 2) 2-3 relevant experiences 3) 3-4 bullet approach 4) Timeline estimate 5) Confident closing with call to action 6) Sound human NOT generic 7) NEVER say Dear Hiring Manager 8) Be direct and confident in first person';
const userPrompt = 'JOB TITLE: ' + title + '\n\nJOB DESCRIPTION:\n' + context + '\n\nWrite the proposal now:';

return [{
  json: {
    title: title,
    link: url,
    description: context,
    openaiBody: JSON.stringify({
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: sysPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.7,
      max_tokens: 600
    })
  }
}];

const proposal = $json.choices?.[0]?.message?.content || 'Failed to generate proposal';
const job = $('Prepare Prompt').first().json;
const title = job.title || 'Unknown';
const link = job.link || '';

const subject = '📝 Upwork Proposal Ready: ' + title;
const emailBody = '<div style="font-family:Segoe UI,Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px"><div style="background:linear-gradient(135deg,#11998e,#38ef7d);padding:20px;border-radius:12px 12px 0 0;text-align:center"><h1 style="color:#fff;margin:0;font-size:22px">📝 Proposal Ready!</h1></div><div style="background:#f8f9fa;padding:20px;border:1px solid #e9ecef"><h2 style="color:#2d3748;margin-top:0">' + title + '</h2>' + (link ? '<div style="margin:15px 0"><a href="' + link + '" style="display:inline-block;background:#4299e1;color:#fff;padding:10px 20px;border-radius:8px;text-decoration:none;font-weight:bold">🔗 Apply on Upwork</a></div>' : '') + '</div><div style="background:#fff;padding:20px;border:1px solid #e9ecef;border-top:none"><h3 style="color:#2d3748;border-bottom:2px solid #11998e;padding-bottom:8px">Your Proposal</h3><div style="background:#f7fafc;padding:15px;border-radius:8px;border-left:4px solid #11998e;white-space:pre-wrap;line-height:1.6">' + proposal + '</div></div><div style="background:#2d3748;color:#a0aec0;padding:15px;border-radius:0 0 12px 12px;text-align:center;font-size:12px"><p>Manual Proposal Generator • n8n</p></div></div>';

return [{ json: { success: true, title, link, proposal, subject, emailBody } }];
